152	  it.todo("sword with exactly enchantment 5 AND cursed → both surcharges apply");
153	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
154	
155	  // === Rounding (in MHPCO's favor — premium rounds up) ===
156	  it.todo("premium calculation yielding 197.5 G → final premium 198 G");
157	
158	  // === Edge case errors for quote ===
159	  it.todo("quote with unknown item type → throws/rejects");
160	
161	  // === Integration examples ===
162	  it.todo("newcomer with a cursed sword (enchantment 3) → premium 165 G");
163	  it.todo("long-standing customer's second contract: cursed sword enchantment 7 → premium 160 G");
164	
165	  // === Claim processing — standard reimbursement ===
166	  it.todo("regular sword damage 500 G → payout 400 G (full minus 100 G deductible)");
167	  it.todo("rune damage 200 G → payout 100 G (full minus 100 G deductible)");
168	
169	  // === Claim — special clauses ===
170	  it.todo("dragon-material sword enchantment 8 damage 1000 G → payout 400 G (high-ench 50% then deductible)");
171	  it.todo("dragon-material sword enchantment 9 damage 1000 G → payout 400 G (50% wins, then deductible)");
172	  it.todo("dragon-material sword enchantment 5 damage 800 G → payout 700 G (full minus deductible)");
173	  it.todo("steel sword enchantment 9 damage 1000 G → payout 400 G (50% then deductible)");
174	
175	  // === Deductible per damage event ===
176	  it.todo("dragon attack damaging sword (500) and amulet (300) → payout 600 G (deductible per item)");
177	
178	  // === Multiple items of the same type ===
179	  it.todo("policy with two swords → insurance sum 2000 G, cap 4000 G; both damaged → separate deductibles");
180	  it.todo("damages array contains more entries of a type than insured → claim rejected (non-zero exit)");
181	
182	  // === Cap exhaustion ===
183	  it.todo("sword + amulet → insurance sum 1600 G, cap 3200 G");
184	  it.todo("cursed sword → cap 2000 G (based on unmodified insurance value)");
185	  it.todo("sword + 3 runes → insurance sum 1750 G (block discount does not affect insurance sum)");
186	  it.todo("sword cap 2000 G, two successive 1500 G claims → first payout 1400 G (cap 600), second payout 600 G (cap 0)");
187	
188	  // === Payout rounding (in MHPCO's favor — payout rounds down) ===
189	  it.todo("payout calculation yielding 350.5 G → final payout 350 G");
190	
191	  // === Claim error cases ===
192	  it.todo("claim references damage entry for item not in policy → rejected");
193	  it.todo("claim contains damage entry with negative amount → rejected");
194	});
