1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type QuoteStep = {
9	  op: "quote";
10	  items: Item[];
11	};
12	
13	export type Step = QuoteStep;
14	
15	export type Scenario = {
16	  customer: { yearsWithMHPCO: number };
17	  steps: Step[];
18	};
19	
20	export type QuoteResult = { premium: number };
21	export type StepResult = QuoteResult;
22	
23	export type ScenarioResult = {
24	  results: StepResult[];
25	};
26	
27	const PROCESSING_FEE = 5;
28	const FIRST_CONTRACT_SURCHARGE_RATE = 0.1;
29	const BLOCK_OF_THREE_DISCOUNT = 15;
30	
31	const BASE_PREMIUM: Record<string, number> = {
32	  sword: 100,
33	  amulet: 60,
34	  staff: 80,
35	  potion: 40,
36	  rune: 25,
37	  moonstone: 25,
38	};
39	
40	const blockOfThreeDiscount = (alikeComponentCount: number): number =>
41	  alikeComponentCount === 3 ? BLOCK_OF_THREE_DISCOUNT : 0;
42	
43	const COMPONENT_TYPES = ["rune", "moonstone"];
44	
45	const countItemsOfType = (items: Item[], type: string): number =>
46	  items.filter((item) => item.type === type).length;
47	
48	const CURSE_SURCHARGE_RATE = 0.5;
49	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
50	const HIGH_ENCHANTMENT_THRESHOLD = 5;
51	const LOYALTY_DISCOUNT_RATE = 0.2;
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	
54	const sumItemSpecificSurcharges = (items: Item[]): number =>
55	  items.reduce((sum, item) => {
56	    const base = BASE_PREMIUM[item.type];
57	    const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
58	    const highEnch =
59	      (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
60	        ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
61	        : 0;
62	    return sum + curse + highEnch;
63	  }, 0);
64	
65	const calculateBasePremium = (items: Item[]): number => {
66	  const subtotal = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
67	  const totalDiscount = COMPONENT_TYPES.reduce(
68	    (sum, type) => sum + blockOfThreeDiscount(countItemsOfType(items, type)),
69	    0,
70	  );
71	  return subtotal - totalDiscount;
72	};
73	
74	const loyaltyDiscount = (basePremium: number, customer: Scenario["customer"]): number =>
75	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
76	
77	const quote = (step: QuoteStep, customer: Scenario["customer"]): QuoteResult => {
78	  const basePremium = calculateBasePremium(step.items);
79	  const itemSurcharges = sumItemSpecificSurcharges(step.items);
80	  const firstContractSurcharge = basePremium * FIRST_CONTRACT_SURCHARGE_RATE;
81	  const premium = Math.ceil(
82	    basePremium +
83	      itemSurcharges +
84	      firstContractSurcharge -
85	      loyaltyDiscount(basePremium, customer) +
86	      PROCESSING_FEE,
87	  );
88	  return { premium };
89	};
90	
91	export const runScenario = (scenario: Scenario): ScenarioResult => {
92	  const results = scenario.steps.map((step) => quote(step, scenario.customer));
93	  return { results };
94	};
